#include <stdio.h>
#include <stdlib.h>
#define MAX 1000
int maxFood = 0;
int pathLength = 0;
int path[MAX * MAX][2];
void dfs(int **grid, int n, int m, int x, int y, int visited[n][m], int currentFood, int currentPathLength, int t, int startX, int startY) {
    if (x == startX && y == startY && currentPathLength > 1) {
        if (currentFood > maxFood) {
            maxFood = currentFood;
            pathLength = currentPathLength;
            for (int i = 0; i < currentPathLength; i++) {
                path[i][0] = x;
                path[i][1] = y;
            }
        }
        return;
    }
    for (int dx = -1; dx <= 1; dx++) {
        for (int dy = -1; dy <= 1; dy++) {
            if (abs(dx) + abs(dy) == 1) {
                int newX = x + dx;
                int newY = y + dy;
                if (newX >= 0 && newX < n && newY >= 0 && newY < m && !visited[newX][newY]) {
                    visited[newX][newY] = 1;
                    if (t % 2 == 1) {
                        dfs(grid, n, m, newX, newY, visited, currentFood + grid[newX][newY], currentPathLength + 1, t + 1, startX, startY);
                    } else {
                        dfs(grid, n, m, newX, newY, visited, currentFood, currentPathLength + 1, t + 1, startX, startY);
                    }
                    visited[newX][newY] = 0;
                }
            }
        }
    }
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int **grid = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            grid[i] = (int *)malloc(m * sizeof(int));
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        maxFood = 0;
        pathLength = 0;
        int visited[n][m];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                visited[i][j] = 0;
            }
        }
        dfs(grid, n, m, 0, 0, visited, grid[0][0], 1, 0, 0, 0);
        dfs(grid, n, m, 0, m - 1, visited, grid[0][m - 1], 1, 0, 0, m - 1);
        dfs(grid, n, m, n - 1, 0, visited, grid[n - 1][0], 1, 0, n - 1, 0);
        dfs(grid, n, m, n - 1, m - 1, visited, grid[n - 1][m - 1], 1, 0, n - 1, m - 1);
        printf("%d\n", maxFood);
        printf("%d\n", pathLength);
        for (int i = 0; i < pathLength; i++) {
            printf("%d %d\n", path[i][0], path[i][1]);
        }
        for (int i = 0; i < n; i++) {
            free(grid[i]);
        }
        free(grid);
    }
    return 0;
}

